spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midX = W / 2;
    var midY = H / 2 - 25;

    // Render Fraction 1: 2/3
    ctx.font = 'bold 20px monospace';
    ctx.fillStyle = '#F3F4F6';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Left fraction: 2 at (midX - 40, midY - 15), 3 at (midX - 40, midY + 15)
    var f1x = midX - 35;
    var f2x = midX + 35;

    // 2
    ctx.fillStyle = (stage === 2 || stage === 4) ? '#F59E0B' : '#F3F4F6'; // Gold
    ctx.fillText('2', f1x, midY - 16);
    // 3
    ctx.fillStyle = (stage === 3 || stage === 4) ? '#10B981' : '#F3F4F6'; // Green
    ctx.fillText('3', f1x, midY + 16);

    // Fraction line 1
    ctx.beginPath();
    ctx.moveTo(f1x - 12, midY);
    ctx.lineTo(f1x + 12, midY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Equal sign
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('=', midX, midY);

    // Right fraction: 4/6
    // 4
    ctx.fillStyle = (stage === 3 || stage === 4) ? '#10B981' : '#F3F4F6'; // Green
    ctx.fillText('4', f2x, midY - 16);
    // 6
    ctx.fillStyle = (stage === 2 || stage === 4) ? '#F59E0B' : '#F3F4F6'; // Gold
    ctx.fillText('6', f2x, midY + 16);

    // Fraction line 2
    ctx.beginPath();
    ctx.moveTo(f2x - 12, midY);
    ctx.lineTo(f2x + 12, midY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.stroke();

    // Draw diagonal cross-product lines
    if (stage === 2 || stage === 4) {
      ctx.beginPath();
      ctx.moveTo(f1x + 5, midY - 12);
      ctx.lineTo(f2x - 5, midY + 12);
      ctx.strokeStyle = 'rgba(245, 158, 11, 0.7)'; // Gold
      ctx.lineWidth = 2.5;
      ctx.stroke();
    }
    if (stage === 3 || stage === 4) {
      ctx.beginPath();
      ctx.moveTo(f1x + 5, midY + 12);
      ctx.lineTo(f2x - 5, midY - 12);
      ctx.strokeStyle = 'rgba(16, 185, 129, 0.7)'; // Green
      ctx.lineWidth = 2.5;
      ctx.stroke();
    }

    // Bottom messages
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.textAlign = 'center';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('Proportion Equation', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Does 2/3 equal 4/6? Let\'s test with cross-products.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('Multiply Extremes: 2 × 6 = 12', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Multiply the top-left (2) and bottom-right (6).', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#10B981';
      ctx.fillText('Multiply Means: 3 × 4 = 12', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Multiply the bottom-left (3) and top-right (4).', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.fillText('12 = 12 (Proportion is True!)', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Since the cross-products are equal, 2/3 and 4/6 form a proportion.', W / 2, H - 22);
    }
  }
};
